 hasShown = true; this.track(prefix + 'Shown'); },\n          start: () => { hasStarted = true; this.track(prefix + 'Start'); },\n          complete: () => { hasCompleted = true; if (hasStarted) this.track(prefix + 'Complete'); },\n          cancel: () => { \n            if (hasShown && !hasCompleted && !hasCanceled) {\n              hasCanceled = true;\n              this.track(prefix + 'Cancel');\n            }\n          }\n        };\n      }\n\n      // Registration Wall tracking\n      setupRegistrationTracking(regForm) {\n        const reg = this.createTracker('trackRegistration');\n        reg.shown();\n        \n        // Start: any auth button click or openpass form\n        regForm.querySelectorAll('.voltax-auth-button, .voltax-auth-google-button')\n          .forEach(btn => btn.addEventListener('click', reg.start, { once: true }));\n\n        // OpenPass iframe tracking\n        const iframe = regForm.querySelector('#voltax-auth-openpass').querySelector('iframe');\n        if (!iframe) {\n          return;\n        }\n        \n        let hasInteracted = false;\n        // Only event that is triggered when the user is interacting with the iframe\n        iframe.addEventListener('mouseenter', () => {\n          hasInteracted = true;\n          reg.start();\n        }, { once: true });\n\n        // Complete: when \"voltax_auth_provider\" is set in local storage\n        // Cancel: when modal closes without completing (modal removed from DOM)\n        const regObserver = new MutationObserver(() => {\n          if (localStorage.getItem('voltax_auth_provider')) {\n            reg.complete();\n            regObserver.disconnect();\n          } else if (!iframe.isConnected) {\n            reg.cancel();\n            regObserver.disconnect();\n          }\n        });\n        regObserver.observe(document.body, { childList: true, subtree: true });\n        \n        // Cancel: leave page without completing (user navigates away)\n        window.addEventListener('beforeunload', reg.cancel);\n      }\n\n      // Newsletter tracking\n      setupNewsletterTracking(newsletterForm) {\n        const nl = this.createTracker('trackNewsletterSignup');\n        nl.shown();\n        \n        const emailInput = newsletterForm.querySelector('input[type=\"text\"]');\n        const submitBtn = newsletterForm.querySelector('.blueConicButton input[type=\"submit\"]');\n        \n        // Start: focus email input\n        if (emailInput) {\n          emailInput.addEventListener('focus', nl.start, { once: true });\n        }\n        \n        // Complete: form submit or button click\n        newsletterForm.addEventListener('submit', nl.complete, { once: true });\n        if (submitBtn) {\n          submitBtn.addEventListener('click', nl.complete, { once: true });\n        }\n        \n        // Cancel: leave page, URL change (finite scroll), or form is removed from DOM\n        window.addEventListener('beforeunload', nl.cancel);\n        window.addEventListener('popstate', nl.cancel);\n        \n        // Cancel: when modal closes without completing (form removed from DOM)\n        const nlObserver = new MutationObserver(() => {\n          if (!newsletterForm.isConnected) {\n            nl.cancel();\n            nlObserver.disconnect();\n          }\n        });\n        nlObserver.observe(document.body, { childList: true, subtree: true });\n        \n        const originalPushState = this.originalPushState;\n        history.pushState = function(...args) {\n          nl.cancel();\n          return originalPushState.apply(history, args);\n        };\n      }\n\n      attachListener() {\n        if (this.isAttached) return;\n        \n        const regForm = this.findRegForm();\n        const newsletterForm = this.findNewsletterForm();\n        \n        if (typeof window.chartbeat !== 'function' || (!regForm && !newsletterForm)) return;\n\n        if (regForm) this.setupRegistrationTracking(document.getElementById('voltax-sign-in'));\n        if (newsletterForm) this.setupNewsletterTracking(document.getElementsByClassName('bcForm')[0]);\n\n        this.isAttached = true;\n        if (this.observer) this.observer.disconnect();\n      }\n\n      init() {\n        this.observer = new MutationObserver(() => this.attachListener());\n        this.observer.observe(document.body, { childList: true, subtree: true });\n        this.attachListener();\n      }\n    }\n\n    window.addEventListener(\"DOMContentLoaded\", () => {\n      new ChartbeatConversionEvents();\n    });\n  ","name":"chartbeatConversionEvents","attributes":null,"loadingType":"async"},{"type":"URL","source":"https://accounts.google.com/gsi/client","name":"googleOAuth","attributes":null,"loadingType":"async"},{"type":"URL","source":"https://edge-auth.microsoft.com/js/ms_auth_client.min.js","name":"microsoftOAuth","attributes":null,"loadingType":"async"},{"type":"code","source":"\n    window.mmBCPageData = {\n      property: 'all_tar_heels',\n      authors: [],\n      pageType: 'ErrorPage',\n      templateName: 'ErrorPageMecca',\n      isRegistrationWall: 'false',\n    };","name":"mmBCPageData","attributes":null,"loadingType":"blocking"},{"type":"URL","source":"https://123p.www.si.com/college/unc/script.js","name":"BlueConic","attributes":null,"loadingType":"async"},{"type":"URL","source":"https://monti-config.bqstreamer.com/loader/loader.min.js","name":"monti","attributes":{"data-publisher":"si","data-site":"all_tar_heels","data-experiment":"","data-isPremium":"0","data-articleId":""},"loadingType":"async"},{"type":"URL","source":"https://assets.minutemediacdn.com/recirculation-widget/prod/mm-recirculation-injector.js","name":"RecirculationWidget","attributes":null,"loadingType":"async"},{"type":"code","name":"update-hem-cookie","source":"\n      (function () {\n        function getCookie(name) {\n          const value = '; ' + document.cookie;\n          const parts = value.split('; ' + name + '=');\n          if (parts.length === 2) {\n   